// EIP: Message Translator
// Converts web / mobile / b2b formats into canonical schema
const body = msg.payload;
const contentType = (msg.req && msg.req.headers && msg.req.headers['content-type']) || '';

let canonical;

if (contentType.includes('xml') || (typeof body === 'string' && body.trim().startsWith('<'))) {
  // B2B XML — simple extraction
  const getString = (tag) => {
    const m = String(body).match(new RegExp('<' + tag + '>([^<]+)</' + tag + '>'));
    return m ? m[1] : null;
  };
  canonical = {
    customerId: getString('customerId') || getString('customer_id'),
    orderType: getString('orderType') || 'b2b',
    currency: getString('currency') || 'USD',
    items: [{ productId: getString('productId') || 'UNKNOWN', quantity: parseInt(getString('quantity') || '1') }]
  };
} else if (body.cust_id || body.itms) {
  // Mobile format
  canonical = {
    customerId: body.cust_id,
    orderType: body.ord_type || 'standard',
    currency: body.curr || 'USD',
    items: body.itms || []
  };
} else {
  // Web format — already canonical
  canonical = body;
}

msg.canonical = canonical;
return msg;

// EIP: Correlation Identifier
// Generate one correlationId for the entire order lifecycle
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const correlationId = uuidv4();
msg.correlationId = correlationId;
msg.trace = [];
msg.stepStart = Date.now();

return msg;

msg.headers = {
  'Content-Type': 'application/json',
  'x-correlation-id': msg.correlationId
};
msg.payload = {
  ...msg.canonical,
  correlationId: msg.correlationId
};
msg.stepStart = Date.now();
return msg;

msg.orderId = msg.payload.orderId;
msg.stepStart = Date.now();
msg.headers = {
  'Content-Type': 'application/json',
  'x-correlation-id': msg.correlationId
};
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  amount: msg.canonical ? msg.canonical.total : 0
};
return msg;

msg.transactionId = msg.payload.transactionId;
msg.trace.push({ step: 'payment', status: 'success', durationMs: Date.now() - msg.stepStart });
msg.stepStart = Date.now();
msg.headers = {
  'Content-Type': 'application/json',
  'x-correlation-id': msg.correlationId
};
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  items: msg.canonical ? msg.canonical.items : []
};
return msg;

msg.trace.push({ step: 'payment', status: 'rejected', durationMs: Date.now() - msg.stepStart });
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  status: 'failed',
  trace: msg.trace
};
msg.statusCode = 200;
return msg;

msg.reservationId = msg.payload.reservationId;
msg.trace.push({ step: 'inventory', status: 'success', durationMs: Date.now() - msg.stepStart });
msg.stepStart = Date.now();
msg.headers = {
  'Content-Type': 'application/json',
  'x-correlation-id': msg.correlationId
};
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  type: 'order_confirmed',
  message: 'Your order has been confirmed'
};
return msg;

msg.trace.push({ step: 'inventory', status: 'unavailable', durationMs: Date.now() - msg.stepStart });
msg.stepStart = Date.now();
// prepare refund call
msg.headers = {
  'Content-Type': 'application/json',
  'x-correlation-id': msg.correlationId
};
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  transactionId: msg.transactionId
};
return msg;

msg.trace.push({ step: 'notification', status: 'success', durationMs: Date.now() - msg.stepStart });
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  status: 'completed',
  trace: msg.trace
};
msg.statusCode = 200;
return msg;

msg.trace.push({ step: 'compensation:payment-refund', status: 'success', durationMs: Date.now() - msg.stepStart });
msg.payload = {
  orderId: msg.orderId,
  correlationId: msg.correlationId,
  status: 'compensated',
  trace: msg.trace
};
msg.statusCode = 200;
return msg;

// EIP: Dead Letter Channel
// Unrecoverable errors land here
node.warn('Dead letter: ' + JSON.stringify(msg.payload));
msg.payload = {
  error: 'Unrecoverable failure',
  correlationId: msg.correlationId || null,
  original: msg.payload
};
return msg;

msg.payload = { status: 'ok', service: 'node-red' };
msg.statusCode = 200;
return msg;
